class Solution:
    def maxProbability(self, n, edges, succProb, start_node, end_node):
        import heapq, math
        if start_node == end_node:
            return 1.0
        graph = [[] for _ in range(n)]
        for (a, b), p in zip(edges, succProb):
            w = -math.log(p) if p > 0 else float('inf')
            graph[a].append((b, w))
            graph[b].append((a, w))
        dist = [float('inf')] * n
        dist[start_node] = 0.0
        heap = [(0.0, start_node)]
        visited = [False] * n
        while heap:
            d, node = heapq.heappop(heap)
            if visited[node]:
                continue
            visited[node] = True
            if node == end_node:
                return math.exp(-d)
            for nxt, w in graph[node]:
                nd = d + w
                if nd < dist[nxt]:
                    dist[nxt] = nd
                    heapq.heappush(heap, (nd, nxt))
        return 0.0

