import heapq

class Solution:
    def maxProbability(self, n, edges, succProb, start_node, end_node):
        graph = [[] for _ in range(n)]
        for (a, b), p in zip(edges, succProb):
            graph[a].append((b, p))
            graph[b].append((a, p))
        prob = [0.0] * n
        prob[start_node] = 1.0
        heap = [(-1.0, start_node)]
        visited = [False] * n
        while heap:
            neg_p, node = heapq.heappop(heap)
            p = -neg_p
            if visited[node]:
                continue
            visited[node] = True
            if node == end_node:
                return p
            for nxt, w in graph[node]:
                if not visited[nxt] and p * w > prob[nxt]:
                    prob[nxt] = p * w
                    heapq.heappush(heap, (-prob[nxt], nxt))
        return prob[end_node]

