var maxProbability = function(n, edges, succProb, start_node, end_node) {
    const graph = Array.from({ length: n }, () => []);
    for (let i = 0; i < edges.length; i++) {
        const [a, b] = edges[i];
        const p = succProb[i];
        graph[a].push([b, p]);
        graph[b].push([a, p]);
    }
    const prob = new Array(n).fill(0);
    prob[start_node] = 1;
    const heap = [[1, start_node]];
    const visited = new Array(n).fill(false);
    function siftDown(i) {
        const len = heap.length;
        while (true) {
            let largest = i, l = 2 * i + 1, r = 2 * i + 2;
            if (l < len && heap[l][0] > heap[largest][0]) largest = l;
            if (r < len && heap[r][0] > heap[largest][0]) largest = r;
            if (largest === i) break;
            [heap[i], heap[largest]] = [heap[largest], heap[i]];
            i = largest;
        }
    }
    function siftUp(i) {
        while (i > 0) {
            const parent = (i - 1) >> 1;
            if (heap[parent][0] >= heap[i][0]) break;
            [heap[i], heap[parent]] = [heap[parent], heap[i]];
            i = parent;
        }
    }
    function push(item) {
        heap.push(item);
        siftUp(heap.length - 1);
    }
    function pop() {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            siftDown(0);
        }
        return top;
    }
    while (heap.length) {
        const [p, node] = pop();
        if (visited[node]) continue;
        visited[node] = true;
        if (node === end_node) return p;
        for (const [nxt, w] of graph[node]) {
            if (!visited[nxt] && p * w > prob[nxt]) {
                prob[nxt] = p * w;
                push([prob[nxt], nxt]);
            }
        }
    }
    return prob[end_node];
};
